mapper.select:
SELECT o.*, u.username, (SELECT GROUP_CONCAT(p.name SEPARATOR ', ') FROM order_item oi LEFT JOIN product p ON oi.product_id = p.id WHERE oi.order_id = o.id) AS product_names FROM orders o LEFT JOIN user u ON o.user_id = u.id
AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND o.user_id = #{userId}
AND o.status = #{status}
AND o.create_time >= #{startDate}
AND o.create_time <= CONCAT(#{endDate}, ' 23:59:59')
ORDER BY o.id DESC
